import{_ as o,c as t,o as i,aj as a}from"./chunks/framework.HLg5PcC2.js";const m=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/changelog.md","filePath":"getting-started/changelog.md"}'),c={name:"getting-started/changelog.md"};function d(s,e,n,r,l,p){return i(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to “Changelog”">​</a></h1><p>New features, API changes, and important fixes in the Primitive platform libraries.</p><h2 id="js-bao-wss-client-v1-4-4-—-2026-05-06" tabindex="-1">js-bao-wss-client v1.4.4 — 2026-05-06 <a class="header-anchor" href="#js-bao-wss-client-v1-4-4-—-2026-05-06" aria-label="Permalink to “js-bao-wss-client v1.4.4 — 2026-05-06”">​</a></h2><ul><li><strong>Default group / collection create is now permissive.</strong> With no custom <code>GroupTypeConfig</code> / <code>CollectionTypeConfig</code>, any signed-in member can create their own group or collection; <code>edit</code> and <code>delete</code> remain creator-only. Apps that need admin-gated creation must now opt in by attaching a rule set whose <code>create</code> rule checks <code>hasRole(&#39;admin&#39;)</code>.</li><li>Group rule-set operation <code>group.list</code> is renamed to <code>group.get</code> (single-resource read), parallel to the earlier <code>collection.list</code> → <code>collection.get</code> rename. Existing rule sets keep working via a backward-compat alias, but newly authored TOML rule sets must use <code>get</code> for the <code>group</code> category. The <code>member.list</code> key is unchanged.</li><li>New <code>client.collectionTypeConfigs</code> and <code>client.databaseTypeConfigs</code> SDK sub-APIs give surface parity with the existing <code>client.groupTypeConfigs</code> for managing per-type rule-set bindings.</li><li><code>client.collections.listDocuments(collectionId)</code> now returns full document metadata (title, createdBy, lastModified, tags, effective permission) in a single round-trip — no more N+1 follow-up <code>documents.get</code> per row.</li><li>Record-route hardening: the 14 direct record HTTP routes (<code>POST records/{save,query,patch,delete,count,batch,aggregate,increment,stringset/*}</code> plus 4 GET introspection routes) are now manager+ only. Member-role callers must go through <code>databases.executeOperation(databaseId, operationName, params)</code> — the operation&#39;s <code>access</code> CEL is the authorization point. Apps already using the registered-operations pattern need no change.</li><li>Collection member removal now broadcasts a <code>docMetadata</code> access-lost frame, so open WebSocket sessions evict immediately instead of silently retaining the YjsRoom connection.</li><li>Accept-invite failures (bad / expired / already-accepted token) collapse to a uniform <code>401 INVITE_TOKEN_INVALID</code> response so the response shape no longer leaks whether a token exists.</li></ul><h2 id="js-bao-v0-4-2-—-2026-05-06" tabindex="-1">js-bao v0.4.2 — 2026-05-06 <a class="header-anchor" href="#js-bao-v0-4-2-—-2026-05-06" aria-label="Permalink to “js-bao v0.4.2 — 2026-05-06”">​</a></h2><ul><li>v2 codegen now auto-promotes <code>auto_assign = true</code> <code>id</code> fields to <code>required = true</code> so the generated attribute interface merges cleanly with <code>BaseModel</code> (no more TS2320 declaration-merge clashes).</li><li>The <code>allModels</code> array exported by the generated <code>index.ts</code> barrel is now typed as <code>Array&lt;typeof BaseModel&gt;</code> instead of <code>unknown[]</code>, so you can pass it straight to <code>JsBaoClient.models</code> without an <code>as</code> cast.</li></ul><h2 id="primitive-app-v2-1-7-patch-—-2026-05-04" tabindex="-1">primitive-app v2.1.7 (patch) — 2026-05-04 <a class="header-anchor" href="#primitive-app-v2-1-7-patch-—-2026-05-04" aria-label="Permalink to “primitive-app v2.1.7 (patch) — 2026-05-04”">​</a></h2><ul><li>The project template now uses a TOML-based model definition approach: declare models in <code>src/models/models.toml</code> and run <code>npx js-bao-codegen-v2</code> to generate typed TypeScript classes — no manual <code>defineModelSchema</code> or <code>getJsBaoConfig</code> wiring needed.</li><li>TOML <code>[models.X.relationships.Y]</code> sections now generate typed traversal methods on model classes (e.g. <code>post.author()</code> returns <code>Promise&lt;Author | null&gt;</code>, <code>author.posts()</code> returns <code>Promise&lt;PaginatedResult&lt;Post&gt;&gt;</code>).</li><li>The generated barrel <code>src/models/index.ts</code> now validates bidirectional sync between <code>models.toml</code> and generated classes — a mismatch at startup throws with a clear error pointing to <code>npx js-bao-codegen-v2</code>.</li><li>Updated peer dependency to <code>js-bao-wss-client@^1.4.4</code>.</li></ul><h2 id="js-bao-v0-4-0-—-2026-05-01" tabindex="-1">js-bao v0.4.0 — 2026-05-01 <a class="header-anchor" href="#js-bao-v0-4-0-—-2026-05-01" aria-label="Permalink to “js-bao v0.4.0 — 2026-05-01”">​</a></h2><ul><li><strong>New <code>js-bao-codegen-v2</code> CLI</strong> — TOML-based code generation. Define models in <code>models.toml</code> and run <code>js-bao-codegen-v2 generate</code> to produce strongly-typed TypeScript classes with auto-registration. Replaces the marker-comment approach of v1 codegen.</li><li><strong><code>js-bao-codegen-v2 migrate</code></strong> — one-shot migration tool that scans a v1-codegen project, generates <code>models.toml</code>, and produces a migration report classifying each model as <code>safe-to-delete</code> or <code>needs-manual-migration</code> (custom methods, function defaults, etc.).</li><li><strong><code>upsertOn</code> in registered database operations</strong> — pass <code>&quot;upsertOn&quot;: &quot;$params.fieldName&quot;</code> in a <code>save</code> operation definition to create-or-update a record by a unique field value instead of requiring an explicit <code>id</code>. Enables idempotent write patterns without client-side lookup.</li><li><strong><code>database.celContext.*</code> CEL alias</strong> — the database CEL context (formerly called &quot;metadata&quot;) is now also accessible as <code>database.celContext.*</code> in access expressions, triggers, and filters. <code>database.metadata.*</code> continues to work as a legacy alias. The TOML field is now <code>celContextAccess</code> (<code>metadataAccess</code> still accepted). The CLI command is now <code>primitive databases cel-context get/update</code> (<code>primitive databases metadata</code> still works).</li></ul><h2 id="primitive-app-v2-1-7-—-2026-04-30" tabindex="-1">primitive-app v2.1.7 — 2026-04-30 <a class="header-anchor" href="#primitive-app-v2-1-7-—-2026-04-30" aria-label="Permalink to “primitive-app v2.1.7 — 2026-04-30”">​</a></h2><ul><li>Models are now defined in <code>src/models/models.toml</code> (TOML schema) and auto-generated into <code>*.generated.ts</code> TypeScript classes — run <code>pnpm codegen</code> after editing the TOML to regenerate</li><li>The <code>allModels</code> barrel in <code>src/models/index.ts</code> is fully auto-generated; adding a model to <code>models.toml</code> and running codegen is all that&#39;s needed to register it with js-bao</li><li>Demo app playground pages have been reorganized under a unified <code>playground/</code> route structure, making it easier to see all API features in one place</li><li><code>useApiLog</code> composable and <code>ApiPlayground</code> wrapper component extracted for consistent API call logging across playground pages</li></ul><h2 id="primitive-app-v2-1-7-—-2026-04-28" tabindex="-1">primitive-app v2.1.7 — 2026-04-28 <a class="header-anchor" href="#primitive-app-v2-1-7-—-2026-04-28" aria-label="Permalink to “primitive-app v2.1.7 — 2026-04-28”">​</a></h2><ul><li>Models are now defined in <code>src/models/models.toml</code> and generated into TypeScript via <code>pnpm models:gen</code> — you no longer write <code>defineModelSchema()</code> by hand; the generated <code>.generated.ts</code> files produce the attribute interface, class declaration, and model-name constant automatically</li><li>Model classes are now pure data containers (no instance methods or getters); business logic belongs in a controller module in <code>src/lib/</code> as free functions — call sites use <code>isOverdue(task)</code> instead of <code>task.isOverdue</code></li><li>The <code>src/models/index.ts</code> barrel is now also auto-generated and handles <code>attachAndRegisterModel</code> registration for all models; always import models from <code>@/models</code> so registration runs exactly once</li><li><code>pnpm models:gen</code> replaces <code>pnpm codegen</code> for model generation; re-run it after any change to <code>models.toml</code></li></ul><h2 id="primitive-app-v2-1-7-—-2026-04-27" tabindex="-1">primitive-app v2.1.7 — 2026-04-27 <a class="header-anchor" href="#primitive-app-v2-1-7-—-2026-04-27" aria-label="Permalink to “primitive-app v2.1.7 — 2026-04-27”">​</a></h2><ul><li>New <code>InviteAcceptPage</code> component (<code>src/pages/InviteAcceptPage.vue</code>, routed at <code>/invite/accept</code>) handles the full invitation acceptance flow — signed-in confirmation, signed-out stash-and-redirect, and all error states (<code>INVITE_TOKEN_EXPIRED</code>, <code>INVITE_ALREADY_ACCEPTED</code>, <code>INVITE_TOKEN_INVALID</code>)</li><li>New <code>inviteToken.ts</code> utility (<code>src/lib/inviteToken.ts</code>) persists invite tokens in <code>sessionStorage</code> across auth round-trips, including cross-tab magic-link flows where the token also rides the OAuth state parameter</li><li>All auth paths in <code>userStore</code> (<code>login</code>, <code>verifyOtp</code>, magic-link callback, <code>registerPasskey</code>) now automatically read and forward the pending invite token so deferred grants resolve in a single server round-trip at sign-in</li><li>Sidebar and user-menu components updated to support collapsible icon mode via <code>group-data-[collapsible=icon]</code> Tailwind classes</li></ul><h2 id="js-bao-wss-client-v1-4-3-—-2026-04-24" tabindex="-1">js-bao-wss-client v1.4.3 — 2026-04-24 <a class="header-anchor" href="#js-bao-wss-client-v1-4-3-—-2026-04-24" aria-label="Permalink to “js-bao-wss-client v1.4.3 — 2026-04-24”">​</a></h2><p>A large cumulative release across invitations, sharing, server-side automation, databases, storage, and CLI. Highlights:</p><p><strong>Invitations and group membership</strong></p><ul><li>Custom invitation email CTAs — <code>invitations.create()</code> (and the deferred branches of <code>documents.setPermissions({ email })</code> and <code>groups.addMember({ email })</code>) return <code>invitationId</code> + <code>inviteToken</code>. <code>invitations.getAcceptToken(id)</code> retrieves the token for any existing invitation.</li><li>Token-based acceptance — <code>invitations.accept(inviteToken)</code> lets an authenticated caller redeem an invitation under a different identity than the email it was sent to. Resolves all linked deferred grants to the caller. <code>AppInvitation.acceptedByUserId</code> records the accepting user.</li><li><code>groups.addMember</code> returns a discriminated union — <code>DirectGroupAdd | DeferredGroupAdd</code>. Branch on <code>status: &quot;added&quot; | &quot;already_member&quot; | &quot;pending_signup&quot;</code>. <code>&quot;already_member&quot;</code> replaces the prior <code>409</code>. The <code>&quot;pending_signup&quot;</code> branch carries <code>invitationId</code> + <code>inviteToken</code>.</li><li><code>groups.removeMember(groupType, groupId, { email })</code> removes the membership if one exists, or cancels the pending <code>DeferredGroupAdd</code> if not — a single call handles both the &quot;already a member&quot; and &quot;pending invite&quot; cases.</li><li><code>documents.listPendingInvitations(documentId)</code> and <code>groups.listPendingInvitations(groupType, groupId)</code> return the deferred grants scoped to one resource.</li><li><code>groups.listUserMemberships(userId)</code> results include <code>name</code> (joined from <code>AppGroup</code>) and optional <code>description</code>; orphan rows are skipped. Accepts <code>{ groupType }</code> for server-side push-down filtering.</li><li>Member invitations with quota — set <code>memberInvitationsEnabled: true</code> on an app to let regular members invite others, capped by <code>memberInvitationLimit</code>. Admins and owners are exempt. New <code>GET /invitations/quota</code> endpoint.</li><li>Document access requests — Google-Docs-style &quot;request access&quot; flow. A 403 on <code>documents.get</code> returns a <code>canRequestAccess</code> hint when applicable. Client methods: <code>documents.requestAccess</code>, <code>listAccessRequests</code>, <code>approveAccessRequest</code>, <code>denyAccessRequest</code>. Owners receive WS + email notifications.</li><li>Bookmarks — generic bookmark model for organizing references to documents, databases, or any target type. <code>client.me.bookmarks.add/remove/rename/list</code> with prefix queries. Documents are auto-bookmarked on creation.</li><li>Email-based document sharing — pass <code>email</code> to <code>client.documents.setPermissions</code> (or <code>setGroupPermission</code>) and the grant resolves automatically when the recipient signs up. Non-members receive an invitation email.</li><li>Invitation acceptance WebSocket event — the <code>invitation</code>/<code>accepted</code> event fires reliably from the GET document path (previously silently dropped on that branch).</li></ul><p><strong>Collections</strong></p><ul><li><code>DocumentCollection</code> exposes <code>collectionType</code> and <code>contextId</code> (both nullable, immutable after create), mirroring <code>AppGroup.groupType</code> + <code>groupId</code>. Collection rule sets reference <code>collection.contextId</code> to express &quot;caller is a member of the group this collection belongs to.&quot; Collection rule sets see a dedicated <code>collection.*</code> CEL namespace, separate from the <code>group.*</code> namespace used by group rule sets.</li><li>Member invitations with quota — set <code>memberInvitationsEnabled: true</code> on an app to let regular members invite others, capped by <code>memberInvitationLimit</code>. Admins and owners are exempt from the quota. New <code>GET /invitations/quota</code> endpoint.</li><li>Document access requests — Google Docs-style &quot;request access&quot; flow. A 403 on <code>documents.get</code> now returns a <code>canRequestAccess</code> hint. New client methods: <code>documents.requestAccess</code>, <code>listAccessRequests</code>, <code>approveAccessRequest</code>, <code>denyAccessRequest</code>. Owners receive WS + email notifications.</li><li>Bookmarks — new generic bookmark model for organizing references to documents, databases, or any target type. <code>client.me.bookmarks.add/remove/rename/list</code> with prefix queries. Documents are auto-bookmarked on creation.</li><li>Invitation acceptance WebSocket event — the <code>invitation</code>/<code>accepted</code> event now fires reliably from the GET document path (previously silently dropped on that branch).</li></ul><p><strong>Server-side automation</strong></p><ul><li>Real-time database subscriptions — <code>db.subscribe</code> / <code>db.unsubscribe</code> over WebSocket. Server-side subscriptions use parameterized CEL filters to broadcast <code>db.change</code> frames to matching connections. Mutations (including those from workflows) automatically trigger subscriptions. Writer&#39;s connection is excluded.</li><li>Cron-triggered workflows — new <code>CronTrigger</code> model and CLI (<code>primitive cron-triggers …</code>). IANA timezone support, overlap skip policy, per-app cap of 50.</li><li><code>applyToQuery</code> database operation — server-side query+mutate in one request with safe-looping truncation signal.</li><li><code>analytics.query</code> workflow step — all 16 analytics query types available from workflows. Default deny, admin/owner bypass, per-run cap of 50.</li><li>Custom email template types — register templates with arbitrary kebab-case names (e.g. <code>&quot;order-confirmation&quot;</code>) via admin API, CLI, or web-admin.</li><li>Inline email mode — the <code>email.send</code> workflow step can now specify <code>subject</code>/<code>htmlBody</code>/<code>textBody</code> directly in the step config, bypassing templates.</li><li>Workflow run steps endpoint — new app-level API exposes persisted step-level data for debugging.</li></ul><p><strong>Databases</strong></p><ul><li><code>executeBatch</code> operation type — apply many individual writes in a single request with CEL access checked per-item.</li><li>Database group permissions — new <code>DatabaseGroupPermission</code> model. <code>databases.get()</code> resolves group access; <code>databases.list()</code> stays direct-only (matches document semantics). New <code>collections.listAll()</code> admin method to retrieve the full-app view.</li></ul><p><strong>Deprecations</strong></p><ul><li><code>importBulk</code> operation type is deprecated. Rename existing configs to <code>executeBatch</code> and review per-item access rules — the new operation type enforces CEL per item rather than across the whole batch.</li></ul><p><strong>Storage</strong></p><ul><li>General-purpose blob buckets — new <code>BlobBucket</code> model for non-document blob storage. Bucket-based storage with TTL tiers, signed URLs, optional CEL access rules, R2-only tracking, full CLI + sync. New <code>blob</code> workflow step.</li></ul><p><strong>CLI</strong></p><ul><li>Project-scoped config with named environments — <code>.primitive/config.json</code> lives in your project. New <code>primitive env</code> commands (<code>create</code>, <code>use</code>, <code>list</code>, <code>delete</code>, <code>rename</code>) for dev/staging/prod environments.</li><li>Test user sign-in — <code>+primitive</code> OTP bypass for automated testing, issues 30-minute tokens. Env-gated, admin-role boundaries, invitation-check hardened.</li></ul><p><strong>Fixes and performance</strong></p><ul><li><code>collections.list()</code> returns only direct-access collections (admin <code>listAll()</code> preserves full-app view).</li><li><code>primitive apps list</code> / <code>primitive use</code> no longer silently truncate at 25 apps.</li><li>WebSocket fanout pagination — removes the ~100-subscriber silent ceiling; adds bounded parallel fanout.</li></ul><p>See <a href="./sharing-and-invitations.html">Sharing and Invitations</a>, <a href="./scheduled-and-realtime-automation.html">Scheduled and Real-Time Automation</a>, and <a href="./blob-buckets.html">Blob Buckets</a> for full walkthroughs.</p><h2 id="js-bao-v0-3-1-—-2026-04-13" tabindex="-1">js-bao v0.3.1 — 2026-04-13 <a class="header-anchor" href="#js-bao-v0-3-1-—-2026-04-13" aria-label="Permalink to “js-bao v0.3.1 — 2026-04-13”">​</a></h2><ul><li>New <code>upsertOn</code> option for <code>save()</code> — pass <code>upsertOn: &quot;fieldName&quot;</code> to create-or-update a record by a unique field value instead of requiring an explicit ID, with transactional lookup to prevent race conditions</li><li>Schema discovery and TOML utilities (<code>discoverSchema</code>, <code>discoverModelNames</code>, <code>schemaToToml</code>, <code>loadSchemaFromTomlString</code>, <code>loadSchemaFromToml</code>) are now re-exported from all bundle entry points (browser, node, cloudflare)</li><li>New YDoc dump utilities for debugging: <code>dumpYDocToPlain()</code> and <code>summarizePlainYDoc()</code> let you inspect document structure as plain JavaScript objects (node bundle)</li><li>Fixed schema discovery failing when YDoc share entries weren&#39;t materialized before instanceof checks</li></ul><h2 id="js-bao-wss-—-2026-04-10" tabindex="-1">js-bao-wss — 2026-04-10 <a class="header-anchor" href="#js-bao-wss-—-2026-04-10" aria-label="Permalink to “js-bao-wss — 2026-04-10”">​</a></h2><ul><li>Model-less documents — you can now work with Yjs documents without pre-defining TypeScript model classes; the server auto-discovers document schema at runtime</li><li>New <code>getDocumentSchema()</code> API and <code>schema-discovered</code> event for client-side schema introspection; pass <code>schemaToml</code> to <code>JsBaoClient</code> for client-side model validation</li><li>Workflow runs triggered via webhooks and <code>workflow.start</code> are now visible through the API (previously hidden)</li><li><code>upsertOn</code> support for conditionally creating or updating records based on field values</li><li>Fixed awareness state keying — <code>sendAwarenessState</code> and <code>_broadcastAwareness</code> now consistently use <code>connectionId</code>, preventing duplicate awareness entries</li><li>Fixed HTTP 400 errors when syncing database records with no top-level field changes</li></ul><h2 id="primitive-app-v2-1-7-—-2026-04-13" tabindex="-1">primitive-app v2.1.7 — 2026-04-13 <a class="header-anchor" href="#primitive-app-v2-1-7-—-2026-04-13" aria-label="Permalink to “primitive-app v2.1.7 — 2026-04-13”">​</a></h2><ul><li>New <code>getOrCreateWithAlias()</code> API replaces the old multi-step document alias flow — handles race conditions server-side, eliminating the need for client-side retry logic</li><li>Fixed passkey credential prompt unexpectedly appearing after OTP sign-in — auth flow now properly cancels pending passkey ceremonies</li><li>New <code>VITE_APP_NAME</code> environment variable to customize the browser tab title</li></ul>',41)])])}const g=o(c,[["render",d]]);export{m as __pageData,g as default};
